+	if err := os.WriteFile(fallback, []byte(testRigsJSON), 0644); err != nil {
+		t.Fatal(err)
+	}
+
+	r, err := BuildPrefixRegistryFromTown(townRoot)
+	if err != nil {
+		t.Fatalf("unexpected error: %v", err)
+	}
